function digits(value) { return String(value || '').replace(/\D+/g, ''); }
function clean(value) { return String(value || '').trim(); }
function upper(value) { return clean(value).toUpperCase(); }
const body = $json.body || $json;
const phoneInput = (body.phone && typeof body.phone === 'object') ? body.phone : {};
const proxyInput = (body.proxy && typeof body.proxy === 'object') ? body.proxy : {};
const cc = digits(phoneInput.country_calling_code || body.country_calling_code || body.cc || body.country_code);
const rawNumber = phoneInput.e164_number || body.e164_number || (typeof body.phone === 'string' ? body.phone : '') || body.phone_number || body.number || phoneInput.national_number || body.national_number || '';
const rawDigits = digits(rawNumber);
let e164 = clean(phoneInput.e164_number || body.e164_number || '');
if (!e164 && clean(rawNumber).startsWith('+')) e164 = clean(rawNumber);
if (!e164 && cc && rawDigits) e164 = `+${rawDigits.startsWith(cc) ? rawDigits : `${cc}${rawDigits}`}`;
if (e164 && !e164.startsWith('+')) e164 = `+${digits(e164)}`;
const countryIso = upper(phoneInput.country_iso2 || body.country_iso2 || body.country_region || body.region);
if (!e164 || !cc || !countryIso) throw new Error('phone must be normalized by wa-app BFF or include e164_number, country_calling_code and country_iso2');
const national = digits(e164).startsWith(cc) ? digits(e164).slice(cc.length) : rawDigits;
const workspaceID = body.workspace_id || 'default';
const jobID = body.job_id || $execution.id;
const proxyStateJSON = clean(body.proxy_state_json || body.state_json || proxyInput.proxy_state_json || proxyInput.state_json || '');
const proxyURL = clean(body.proxy_url || proxyInput.proxy_url || '');
return [{ json: {
  workspace_id: workspaceID,
  job_id: jobID,
  request_id: body.request_id || $execution.id,
  actor_id: body.actor_id || '',
  country_calling_code: cc,
  country_code: cc,
  country_iso2: countryIso,
  country_region: countryIso,
  region: countryIso,
  phone: { e164_number: e164, country_calling_code: cc, national_number: national, country_iso2: countryIso },
  proxy_state_json: proxyStateJSON,
  state_json: proxyStateJSON,
  proxy_url: proxyURL,
  include_transient_fingerprint: true,
  purpose: 'WA_REGISTRATION',
} }];

const event = $json.body || $json;
const code = String(event.otp || event.code || event.verification_code || '').trim();
return [{ json: { otp_received: Boolean(code), verification_code: code, raw_event: event } }];

const persist = $input.first().json.body || $input.first().json || {};
const submit = $('Submit SMS OTP').first().json.body || $('Submit SMS OTP').first().json || {};
const registration = submit.registration || submit;
const loginState = persist.login_state || submit.login_state || {};
const submitStatus = registration.status || submit.status || '';
const submitOK = submit.success === true || ['REGISTRATION_STATUS_REGISTERED','REGISTERED','registered'].includes(submitStatus);
const persistOK = persist.success === true && ['LOGIN_STATE_STATUS_ACTIVE','ACTIVE','active'].includes(loginState.status || persist.status || '');
const ok = submitOK && persistOK;
const status = ok ? 'REGISTERED' : (submitOK ? 'LOGIN_STATE_PERSIST_FAILED' : 'OTP_SUBMIT_FAILED');
const message = ok ? '' : (persist.error_message || submit.error_message || persist.error?.message || submit.error?.message || 'registration login state is not active');
const runtimeProxy = $('Run WA US Dynamic IP').first().json || {};
const proxy = { proxy_mode: runtimeProxy.proxy_mode || 'US_RANDOM_DYNAMIC_IP', country_code: runtimeProxy.country_code || 'US' };
return [{ json: { success: ok, status, error_message: message, phone: $('Normalize Registration Input').first().json.phone, wa_account_id: (($('Commit Fingerprint To Profile').first().json.body || $('Commit Fingerprint To Profile').first().json).wa_account_id || ''), client_profile_id: (($('Commit Fingerprint To Profile').first().json.body || $('Commit Fingerprint To Profile').first().json).client_profile_id || ''), registration, login_state: loginState, proxy } }];

const response = $('Request SMS OTP').first().json.body || $('Request SMS OTP').first().json || {};
const commit = $('Commit Fingerprint To Profile').first().json.body || $('Commit Fingerprint To Profile').first().json || {};
const verification = response.verification_request || {};
return [{ json: {
  success: false,
  status: 'OTP_REQUEST_FAILED',
  error_message: response.error_message || response.error?.message || 'sms otp request failed',
  phone: $('Normalize Registration Input').first().json.phone,
  wa_account_id: commit.wa_account_id || response.wa_account_id || verification.wa_account_id || '',
  client_profile_id: commit.client_profile_id || response.client_profile_id || verification.client_profile_id || '',
  verification_request_id: response.verification_request_id || verification.verification_request_id || '',
  data: response,
} }];

const commit = $('Commit Fingerprint To Profile').first().json.body || $('Commit Fingerprint To Profile').first().json || {};
const request = $('Request SMS OTP').first().json.body || $('Request SMS OTP').first().json || {};
const verification = request.verification_request || {};
return [{ json: {
  success: false,
  status: 'OTP_TIMEOUT',
  error_message: 'otp was not provided before wait timeout',
  phone: $('Normalize Registration Input').first().json.phone,
  wa_account_id: commit.wa_account_id || verification.wa_account_id || '',
  client_profile_id: commit.client_profile_id || verification.client_profile_id || '',
  verification_request_id: request.verification_request_id || verification.verification_request_id || '',
} }];
